     5→//! VVC Commit - Core commit infrastructure
     6→//!
     7→//! Provides atomic commit workflow: lock, stage, guard, commit.
     8→//! Used by vvx commit and JJK commands for consistent commit handling.
     9→//!
    10→//! ## Usage Patterns
    11→//!
    12→//! ### Simple commit (lock acquired and released automatically):
    13→//! ```ignore
    14→//! let exit_code = vvc::commit(&args);
    15→//! ```
    16→//!
    17→//! ### Protected operation (hold lock across multiple steps):
    18→//! ```ignore
    19→//! let lock = vvc::vvcc_CommitLock::vvcc_acquire()?;
    20→//! // ... do work while holding lock ...
    21→//! let hash = lock.vvcc_commit(&args)?;
    22→//! // lock released when dropped
    23→//! ```
    24→//!
    25→//! Exit codes:
    26→//!   0 - Success (commit hash printed to stdout)
    27→//!   1 - Failure (lock held, guard failed, claude failed, commit failed)
    28→
    29→use std::process::Command;
    30→
    31→use crate::vvcg_guard;
    32→
    33→/// Lock reference path for commit operations
    34→const VVCC_LOCK_REF: &str = "refs/vvg/locks/vvx";
    35→
    36→/// Arguments for commit operation
    37→///
    38→/// Note: No Default impl - callers must explicitly specify all fields,
    39→/// including size limits. Use VVCG_SIZE_LIMIT/VVCG_WARN_LIMIT constants
    40→/// for standard behavior.
    41→#[derive(Debug, Clone)]
    42→pub struct vvcc_CommitArgs {
    43→    /// Prefix string to prepend to commit message (e.g., "[jj:BRAND][F00/silks]")
    44→    pub prefix: Option<String>,
    45→    /// Commit message; if absent, invoke claude to generate from diff
    46→    pub message: Option<String>,
    47→    /// Allow empty commits (for chalk markers)
    48→    pub allow_empty: bool,
    49→    /// Skip 'git add -A' (respect pre-staged files)
    50→    pub no_stage: bool,
    51→    /// Size limit in bytes (use VVCG_SIZE_LIMIT for standard behavior)
    52→    pub size_limit: u64,
    53→    /// Warning threshold in bytes (use VVCG_WARN_LIMIT for standard behavior)
    54→    pub warn_limit: u64,
    55→}
    56→
    57→/// RAII guard that holds the commit lock.
    58→///
    59→/// The lock is automatically released when the guard is dropped, ensuring
    60→/// no code path can leak the lock. Use this when you need to hold the lock
    61→/// across multiple operations (e.g., modify gallops, then commit).
    62→///
    63→/// ## Example
    64→/// ```ignore
    65→/// let lock = vvcc_CommitLock::vvcc_acquire()?;
    66→/// // Do protected work here...
    67→/// let hash = lock.vvcc_commit(&args)?;
    68→/// // Lock released when `lock` goes out of scope
    69→/// ```
    70→pub struct vvcc_CommitLock {
    71→    /// Private field prevents external construction
    72→    _private: (),
    73→}
    74→
    75→impl vvcc_CommitLock {
    76→    /// Acquire the commit lock.
    77→    ///
    78→    /// Returns `Err` if the lock is already held by another operation.
    79→    /// The lock is held until this `vvcc_CommitLock` is dropped.
    80→    pub fn vvcc_acquire() -> Result<Self, String> {
    81→        zvvcc_acquire_lock()?;
    82→        Ok(vvcc_CommitLock { _private: () })
    83→    }
    84→
    85→    /// Perform a commit while holding the lock.
    86→    ///
    87→    /// This does NOT release the lock - the caller retains the guard
    88→    /// and can perform additional operations if needed.
    89→    ///
    90→    /// Returns the commit hash on success.
    91→    pub fn vvcc_commit(&self, args: &vvcc_CommitArgs) -> Result<String, String> {
    92→        zvvcc_run_commit_workflow(args)
    93→    }
    94→}
    95→
    96→impl Drop for vvcc_CommitLock {
    97→    fn drop(&mut self) {
    98→        zvvcc_release_lock();
    99→    }
   100→}
   101→
   102→/// Acquire the commit lock using git update-ref
   103→fn zvvcc_acquire_lock() -> Result<(), String> {
   104→    let head_output = Command::new("git")
   105→        .args(["rev-parse", "HEAD"])
   106→        .output()
   107→        .map_err(|e| format!("Failed to run git rev-parse: {}", e))?;
   108→
   109→    let lock_value = if head_output.status.success() {
   110→        String::from_utf8_lossy(&head_output.stdout).trim().to_string()
   111→    } else {
   112→        "0000000000000000000000000000000000000000".to_string()
   113→    };
   114→
   115→    let result = Command::new("git")
   116→        .args(["update-ref", VVCC_LOCK_REF, &lock_value, ""])
   117→        .output()
   118→        .map_err(|e| format!("Failed to run git update-ref: {}", e))?;
   119→
   120→    if result.status.success() {
   121→        eprintln!("commit: lock acquired");
   122→        Ok(())
   123→    } else {
   124→        Err("Another commit in progress - lock held".to_string())
   125→    }
   126→}
   127→
   128→/// Release the commit lock
   129→fn zvvcc_release_lock() {
   130→    let _ = Command::new("git")
   131→        .args(["update-ref", "-d", VVCC_LOCK_REF])
   132→        .output();
   133→    eprintln!("commit: lock released");
   134→}
   135→
   136→/// Stage all changes including untracked files with 'git add -A'
   137→fn zvvcc_stage_changes() -> Result<(), String> {
   138→    let result = Command::new("git")
   139→        .args(["add", "-A"])
   140→        .output()
   141→        .map_err(|e| format!("Failed to run git add: {}", e))?;
   142→
   143→    if result.status.success() {
   144→        eprintln!("commit: staged all changes");
   145→        Ok(())
   146→    } else {
   147→        Err(format!(
   148→            "git add -A failed: {}",
   149→            String::from_utf8_lossy(&result.stderr)
   150→        ))
   151→    }
   152→}
   153→
   154→/// Check if there are staged changes
   155→fn zvvcc_has_staged_changes() -> Result<bool, String> {
   156→    let result = Command::new("git")
   157→        .args(["diff", "--cached", "--quiet"])
   158→        .output()
   159→        .map_err(|e| format!("Failed to run git diff: {}", e))?;
   160→
   161→    Ok(!result.status.success())
   162→}
   163→
   164→/// Run size guard check on staged content
   165→fn zvvcc_run_guard(args: &vvcc_CommitArgs) -> Result<(), String> {
   166→    let guard_args = vvcg_guard::vvcg_GuardArgs {
   167→        limit: args.size_limit,
   168→        warn: args.warn_limit,
   169→    };
   170→
   171→    let result = vvcg_guard::vvcg_run(&guard_args, None);
   172→
   173→    match result {
   174→        0 => Ok(()),
   175→        1 => Err("Staged content exceeds size limit".to_string()),
   176→        2 => {
   177→            eprintln!("commit: WARNING - staged content near size limit");
   178→            Ok(())
   179→        }
   180→        _ => Err(format!("Guard returned unexpected code: {}", result)),
   181→    }
   182→}
   183→
   184→/// Get the staged diff for commit message generation
   185→fn zvvcc_get_staged_diff() -> Result<String, String> {
   186→    let output = Command::new("git")
   187→        .args(["diff", "--cached"])
   188→        .output()
   189→        .map_err(|e| format!("Failed to run git diff: {}", e))?;
   190→
   191→    if !output.status.success() {
   192→        return Err("git diff --cached failed".to_string());
   193→    }
   194→
   195→    Ok(String::from_utf8_lossy(&output.stdout).to_string())
   196→}
   197→
   198→/// Generate commit message using claude CLI
   199→fn zvvcc_generate_message_with_claude(diff: &str) -> Result<String, String> {
   200→    let prompt = format!(
   201→        "Generate a concise commit message for this diff:\n\n<diff>\n{}\n</diff>\n\nRespond with only the commit message, no explanation.",
   202→        diff
   203→    );
   204→
   205→    eprintln!("commit: invoking claude for commit message...");
   206→
   207→    let output = Command::new("claude")
   208→        .args([
   209→            "--print",
   210→            "--system-prompt",
   211→            "Output only a conventional git commit message. No explanation or commentary. Do not wrap in markdown code blocks.",
   212→            "--model",
   213→            "haiku",
   214→            "--no-session-persistence",
   215→            &prompt,
   216→        ])
   217→        .output()
   218→        .map_err(|e| format!("Failed to invoke claude: {}", e))?;
   219→
   220→    if !output.status.success() {
   221→        let stderr = String::from_utf8_lossy(&output.stderr);
   222→        return Err(format!("claude --print failed: {}", stderr));
   223→    }
   224→
   225→    let message = String::from_utf8_lossy(&output.stdout).trim().to_string();
   226→
   227→    // Strip markdown code blocks if Claude wrapped the response
   228→    let message = if message.starts_with("```") {
   229→        let after_opening = message.find('\n').map(|i| i + 1).unwrap_or(0);
   230→        let before_closing = message.rfind("```").unwrap_or(message.len());
   231→        if before_closing > after_opening {
   232→            message[after_opening..before_closing].trim().to_string()
   233→        } else {
   234→            message
   235→        }
   236→    } else {
   237→        message
   238→    };
   239→
   240→    // Strip Co-Authored-By trailer if Claude CLI added it from global settings
   241→    let message: String = message
   242→        .lines()
   243→        .filter(|line| !line.starts_with("Co-Authored-By:"))
   244→        .collect::<Vec<_>>()
   245→        .join("\n")
   246→        .trim()
   247→        .to_string();
   248→
   249→    if message.is_empty() {
   250→        return Err("claude returned empty message".to_string());
   251→    }
   252→
   253→    eprintln!("commit: claude generated message");
   254→    Ok(message)
   255→}
   256→
   257→/// Format the full commit message with prefix and co-author
   258→fn zvvcc_format_commit_message(prefix: Option<&str>, message: &str) -> String {
   259→    let mut full_message = String::new();
   260→
   261→    if let Some(p) = prefix {
   262→        full_message.push_str(p);
   263→    }
   264→
   265→    full_message.push_str(message);
   266→
   267→    full_message
   268→}
   269→
   270→/// Execute the git commit
   271→fn zvvcc_execute_commit(message: &str, allow_empty: bool) -> Result<String, String> {
   272→    let mut args = vec!["commit", "-m", message];
   273→
   274→    if allow_empty {
   275→        args.push("--allow-empty");
   276→    }
   277→
   278→    let output = Command::new("git")
   279→        .args(&args)
   280→        .output()
   281→        .map_err(|e| format!("Failed to run git commit: {}", e))?;
   282→
   283→    if !output.status.success() {
   284→        let stderr = String::from_utf8_lossy(&output.stderr);
   285→        return Err(format!("git commit failed: {}", stderr));
   286→    }
   287→
   288→    let hash_output = Command::new("git")
   289→        .args(["rev-parse", "HEAD"])
   290→        .output()
   291→        .map_err(|e| format!("Failed to get commit hash: {}", e))?;
   292→
   293→    if !hash_output.status.success() {
   294→        return Err("Failed to retrieve commit hash".to_string());
   295→    }
   296→
   297→    Ok(String::from_utf8_lossy(&hash_output.stdout)
   298→        .trim()
   299→        .to_string())
   300→}
   301→
   302→/// Run the commit workflow.
   303→///
   304→/// Returns exit code: 0 for success, 1 for failure.
   305→/// On success, prints commit hash to stdout.
   306→///
   307→/// This is the simple API that acquires and releases the lock automatically.
   308→/// For operations that need to hold the lock across multiple steps, use
   309→/// `vvcc_CommitLock::vvcc_acquire()` instead.
   310→pub fn vvcc_run(args: &vvcc_CommitArgs) -> i32 {
   311→    let lock = match vvcc_CommitLock::vvcc_acquire() {
   312→        Ok(l) => l,
   313→        Err(e) => {
   314→            eprintln!("commit: error: {}", e);
   315→            return 1;
   316→        }
   317→    };
   318→
   319→    match lock.vvcc_commit(args) {
   320→        Ok(hash) => {
   321→            println!("{}", hash);
   322→            eprintln!("commit: success");
   323→            0
   324→        }
   325→        Err(e) => {
   326→            eprintln!("commit: error: {}", e);
   327→            1
   328→        }
   329→    }
   330→    // lock dropped here, releasing the git ref lock
   331→}
   332→
   333→/// Inner workflow that can return Result for cleaner error handling
   334→fn zvvcc_run_commit_workflow(args: &vvcc_CommitArgs) -> Result<String, String> {
   335→    if !args.no_stage {
   336→        zvvcc_stage_changes()?;
   337→    }
   338→
   339→    if !args.allow_empty && !zvvcc_has_staged_changes()? {
   340→        return Err("Nothing to commit".to_string());
   341→    }
   342→
   343→    zvvcc_run_guard(args)?;
   344→
   345→    let message = match &args.message {
   346→        Some(m) => m.clone(),
   347→        None => {
   348→            let diff = zvvcc_get_staged_diff()?;
   349→            if diff.is_empty() && !args.allow_empty {
   350→                return Err("No diff to generate message from".to_string());
   351→            }
   352→            zvvcc_generate_message_with_claude(&diff)?
   353→        }
   354→    };
   355→
   356→    let full_message = zvvcc_format_commit_message(args.prefix.as_deref(), &message);
   357→
   358→    zvvcc_execute_commit(&full_message, args.allow_empty)
   359→}
