    77→/// Pace-level chalk markers (single-letter codes)
    78→/// - A = APPROACH: proposed approach before work begins
    79→/// - W = WRAP: pace completion summary
    80→/// - F = FLY: autonomous execution began (bridled pace)
    81→/// - B = BRIDLE: pace transitioned to bridled state
    82→/// - d = discussion: significant decision (lowercase, can be heat-level too)
    83→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    84→pub enum jjrn_ChalkMarker {
    85→    Approach,
    86→    Wrap,
    87→    Fly,
    88→    Bridle,
    89→    Discussion,
    90→}
    91→
    92→impl jjrn_ChalkMarker {
    93→    /// Parse marker from string (accepts both single letter and full word)
    94→    pub fn jjrn_parse(s: &str) -> Result<Self, String> {
    95→        match s {
    96→            "A" | "a" | "APPROACH" | "approach" | "Approach" => Ok(jjrn_ChalkMarker::Approach),
    97→            "W" | "w" | "WRAP" | "wrap" | "Wrap" => Ok(jjrn_ChalkMarker::Wrap),
    98→            "F" | "f" | "FLY" | "fly" | "Fly" => Ok(jjrn_ChalkMarker::Fly),
    99→            "B" | "b" | "BRIDLE" | "bridle" | "Bridle" => Ok(jjrn_ChalkMarker::Bridle),
   100→            "d" | "D" | "DISCUSSION" | "discussion" | "Discussion" => Ok(jjrn_ChalkMarker::Discussion),
   101→            _ => Err(format!(
   102→                "Invalid marker type '{}'. Valid: A(pproach), W(rap), F(ly), B(ridle), d(iscussion)",
   103→                s
   104→            )),
   105→        }
   106→    }
   107→
   108→    /// Get single-letter code for commit message
   109→    pub fn jjrn_code(&self) -> char {
   110→        match self {
   111→            jjrn_ChalkMarker::Approach => 'A',
   112→            jjrn_ChalkMarker::Wrap => 'W',
   113→            jjrn_ChalkMarker::Fly => 'F',
   114→            jjrn_ChalkMarker::Bridle => 'B',
   115→            jjrn_ChalkMarker::Discussion => 'd',
   116→        }
   117→    }
   118→
   119→    /// Get full display string for the marker (for user-facing output)
   120→    pub fn jjrn_as_str(&self) -> &'static str {
   121→        match self {
   122→            jjrn_ChalkMarker::Approach => "APPROACH",
   123→            jjrn_ChalkMarker::Wrap => "WRAP",
   124→            jjrn_ChalkMarker::Fly => "FLY",
   125→            jjrn_ChalkMarker::Bridle => "BRIDLE",
   126→            jjrn_ChalkMarker::Discussion => "discussion",
   127→        }
   128→    }
   129→
   130→    /// Returns true if this marker type requires a pace to be specified
   131→    pub fn jjrn_requires_pace(&self) -> bool {
   132→        match self {
   133→            jjrn_ChalkMarker::Approach | jjrn_ChalkMarker::Wrap | jjrn_ChalkMarker::Fly | jjrn_ChalkMarker::Bridle => true,
   134→            jjrn_ChalkMarker::Discussion => false,
   135→        }
   136→    }
   137→}
